const btnComprar=document.querySelector("button#btnBuy"),btnVolver=document.querySelector("button#btnReturn"),totalCarrito=document.querySelector("td#totalPrice"),tableBody=document.querySelector("tbody#tableBody"),carrito=recuperarCarrito();function armarFilaHTML(t){return`<tr data-filaCodigo="${t.codigo}">\n                <td id="pImagen">${t.imagen}</td>\n                <td id="nombre">${t.nombre}</td>\n                <td id="price">$ ${t.precio.toLocaleString()}</td>\n                <td id="categoría">${t.categoria}</td>\n                <td id="delButton" \n                    data-codigo="${t.codigo}" \n                    title="Clic para eliminar">\n                    ⛔️\n                </td>\n                <td id="editButton" \n                    data-codigo="${t.id}" \n                    title="Clic para Modificar">\n                    ✍️\n                </td>\n            </tr>`}function mostrarToast(t,r){Swal.fire({toast:!0,position:"top-end",showConfirmButton:!1,timer:2800,timerProgressBar:!0,theme:"dark",icon:t,text:r.trim()})}function crearFilaProducto(t){return`<tr>\n                <td id="pImagen">${t.imagen}</td>\n                <td id="nombre">${t.nombre}</td>\n                <td id="price">$ ${t.precio}</td>\n                <td id="delButton" \n                    data-codigo="${t.codigo}" \n                    title="Clic para eliminar">\n                    ❌\n                </td>\n            </tr>`}function guardarCarrito(){localStorage.setItem("carritoTeclab",JSON.stringify(carrito))}function recuperarCarrito(){return JSON.parse(localStorage.getItem("carritoTeclab"))||[]}function calculateTotalAmount(){return carrito.reduce(((t,r)=>t+r.precio),0).toLocaleString("es-AR",{style:"currency",currency:"ARS"})}function cargarCarritoCompras(){if(carrito.length>0){let t="";carrito.forEach((r=>t+=crearFilaProducto(r))),tableBody.innerHTML=t,totalCarrito.textContent=calculateTotalAmount(),activarEventosClickQuitarProd(),btnComprar.removeAttribute("disabled")}else retornarAhome()}function retornarAhome(){location.href="index.html"}function activarEventosClickQuitarProd(){const t=document.querySelectorAll("td#delButton");t.length>0&&t.forEach((t=>{t.addEventListener("click",(()=>{let r=carrito.findIndex((r=>r.codigo===t.dataset.codigo)),o=carrito.splice(r,1);guardarCarrito(),mostrarToast("info",`${o[0].nombre} quitado del array.`),cargarCarritoCompras()}))}))}cargarCarritoCompras(),btnComprar.addEventListener("click",(()=>{Swal.fire({icon:"success",title:"Compra finalizada",text:"Muchas gracias por elegirnos. El carrito de producto(s) será enviado a su domicilio.",confirmButtonText:"Aceptar"}).then((t=>{carrito.length=0,localStorage.removeItem("carritoTeclab"),setTimeout((()=>retornarAhome()),1500)}))})),btnVolver.addEventListener("click",(()=>retornarAhome()));